    // METHODOLOGY EMPLOYED:
    // Uses empirical correlation

    // REFERENCES:
    //  ASHRAE 1311-RP

    Real64 const ARA(std::abs(RA));
    if (ARA <= 10000.0) {
        return 1.0 + 1.75967e-10 * std::pow(ARA, 2.2984755);
    }
    if (ARA <= 50000.0) {
