struct MinHeap {
    vector<int> h;
    void push(int v) {
        h.push_back(v);
        int i = (int)h.size() - 1;
        while (i > 0) {
            int p = (i - 1) / 2;
            if (h[p] <= h[i]) break;
            int t = h[p]; h[p] = h[i]; h[i] = t;
            i = p;
        }
    }
    int top() const { return h[0]; }
    int size() const { return (int)h.size(); }
    int pop() {
        int r = h[0];
        h[0] = h[h.size() - 1];
        h.pop_back();
        int i = 0; int n = (int)h.size();
        while (true) {
            int l = 2*i+1, ri = 2*i+2, s = i;
            if (l < n && h[l] < h[s]) s = l;
            if (ri < n && h[ri] < h[s]) s = ri;
            if (s == i) break;
            int t = h[s]; h[s] = h[i]; h[i] = t;
            i = s;
        }
        return r;
    }
};
```

