struct Stopwatch2 {
    double elapsed;
    bool running;
    Stopwatch2() : elapsed(0.0), running(false) {}
    void start() {
        running = true;
    }
    void advance(double dt) {
        if (running) elapsed = elapsed + dt;
    }
    void stop() {
        running = false;
    }
    void reset() {
        elapsed = 0.0;
        running = false;
    }
    double read() const {
        return elapsed;
    }
};
```

