int build_and_query(const std::vector<int>& keys, const std::vector<int>& vals, const std::vector<int>& queries){
    std::map<int,int> m;
    for (size_t i = 0; i < keys.size(); ++i) m[keys[i]] = vals[i];
    int total = 0;
    for (size_t i = 0; i < queries.size(); ++i){
        std::map<int,int>::iterator it = m.find(queries[i]);
        if (it != m.end()) total += it->second;
    }
    return total;
}
```

