int char_class_counts(const std::string& s, const std::string& cls){
    std::map<std::string,int> counts;
    for (size_t i = 0; i < s.size(); ++i){
        char c = s[i];
        std::string k;
        if (c >= '0' && c <= '9') k = "digit";
        else if ((c >= 'a' && c <= 'z') || (c >= 'A' && c <= 'Z')) k = "alpha";
        else k = "other";
        counts[k] += 1;
    }
    std::map<std::string,int>::iterator it = counts.find(cls);
    if (it == counts.end()) return 0;
    return it->second;
}
```

