int count_by_parity(const std::vector<int>& nums, int which){
    std::map<int,int> counts;
    for (size_t i = 0; i < nums.size(); ++i){
        int p = ((nums[i] % 2) + 2) % 2;
        counts[p] += 1;
    }
    std::map<int,int>::iterator it = counts.find(which);
    if (it == counts.end()) return 0;
    return it->second;
}
```

