```cpp
int bucket_of(int score){ return score / 10; }

int histogram_count(const std::vector<int>& scores, int bucket){
    std::map<int,int> hist;
    for (size_t i = 0; i < scores.size(); ++i) hist[bucket_of(scores[i])] += 1;
    std::map<int,int>::iterator it = hist.find(bucket);
    if (it == hist.end()) return 0;
    return it->second;
}
```

