    if(code>=100 && code<200) return HTTP_INFO;
    if(code>=200 && code<300) return HTTP_OK;
    if(code>=300 && code<400) return HTTP_REDIRECT;
    if(code>=400 && code<500) return HTTP_CLIENT_ERR;
    if(code>=500 && code<600) return HTTP_SERVER_ERR;
    return HTTP_UNKNOWN;
}
```

