std::string key_with_max_value(const std::vector<std::string>& keys, const std::vector<long>& vals){
    std::map<std::string,long> m;
    for(size_t i=0;i<keys.size();++i) m[keys[i]] = vals[i];
    std::string best = "";
    long bestv = 0;
    bool first = true;
    for(std::map<std::string,long>::const_iterator it=m.begin(); it!=m.end(); ++it){
        if(first || it->second > bestv){ best = it->first; bestv = it->second; first = false; }
    }
    return best;
}
```

