```cpp
int longest_char_run(const std::string& s, char target){
    std::map<char,int> best;
    int cur = 0;
    char prev = 0;
    for (size_t i = 0; i < s.size(); ++i){
        char c = s[i];
        if (c == prev) cur += 1; else cur = 1;
        if (cur > best[c]) best[c] = cur;
        prev = c;
    }
    if (best.find(target) == best.end()) return 0;
    return best[target];
}
```

