int majority_element(const std::vector<int>& nums){
    std::map<int,int> counts;
    int n = (int)nums.size();
    for (size_t i = 0; i < nums.size(); ++i){
        counts[nums[i]] += 1;
        if (counts[nums[i]] * 2 > n) return nums[i];
    }
    return -1;
}
```

