template <typename T>
struct MinMax {
    T lo;
    T hi;
};
template <typename T>
MinMax<T> minmax_generic(const T* xs, int n){
    MinMax<T> r;
    r.lo = xs[0];
    r.hi = xs[0];
    for (int i = 1; i < n; ++i){
        if (xs[i] < r.lo) r.lo = xs[i];
        if (r.hi < xs[i]) r.hi = xs[i];
    }
    return r;
}
```

