int neighbor_count(const std::vector<int>& src, const std::vector<int>& dst, int node){
    std::map<int, std::map<int,int>> adj;
    for (size_t i = 0; i < src.size(); ++i){
        adj[src[i]][dst[i]] = 1;
        adj[dst[i]][src[i]] = 1;
    }
    if (adj.find(node) == adj.end()) return 0;
    return (int)adj[node].size();
}
```

