long prefix_sum_range(const std::vector<int>& a, int lo, int hi){
    std::map<int,long> pre;
    long run = 0;
    pre[0] = 0;
    for (size_t i = 0; i < a.size(); ++i){ run += a[i]; pre[(int)i + 1] = run; }
    long left = (pre.find(lo) != pre.end()) ? pre[lo] : 0;
    long right = (pre.find(hi) != pre.end()) ? pre[hi] : 0;
    return right - left;
}
```

